const input = $input.first().json;
const workflowId = String(input.workflowId || '').trim();
if (!workflowId) throw new Error('workflowId is required.');
return [{
  json: {
    workflowId,
    workflowName: input.workflowName != null ? String(input.workflowName) : '',
    description: input.description != null ? String(input.description) : '',
    active: input.active != null ? String(input.active) : '',
    validateRpc: {
      jsonrpc: '2.0',
      id: 1,
      method: 'tools/call',
      params: { name: 'get_workflow_details', arguments: { workflowId } },
    },
  },
}];

function sanitizeJsString(s) {
  return String(s)
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '');
}
function slugify(name) {
  const x = String(name || 'workflow').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  return x || 'workflow';
}
function incomingCount(nodeName, connections) {
  let c = 0;
  for (const [, out] of Object.entries(connections || {})) {
    for (const edge of out?.main?.[0] || []) {
      if (edge?.node === nodeName) c++;
    }
  }
  return c;
}
function linearPath(root, connections, maxSteps) {
  const path = [root];
  let cur = root;
  const seen = new Set(path);
  for (let i = 0; i < maxSteps; i++) {
    const nexts = connections?.[cur]?.main?.[0] || [];
    if (!nexts.length) break;
    if (nexts.length > 1) throw new Error('Branching workflows are not supported by this helper.');
    const nxt = nexts[0]?.node;
    if (!nxt || seen.has(nxt)) throw new Error('Cycle or broken connection chain.');
    seen.add(nxt);
    path.push(nxt);
    cur = nxt;
  }
  return path;
}
function chooseTriggerRootName(nodes, connections) {
  const roots = (nodes || []).filter((n) => incomingCount(n.name, connections) === 0);
  if (!roots.length) throw new Error('Could not locate a root trigger (no incoming edges).');
  const trigLike = roots.filter((n) => {
    const t = String(n.type || '');
    return t.endsWith('Trigger')
      || t.includes('postgresTrigger')
      || t.endsWith('.webhook')
      || t.includes('chatTrigger')
      || t.endsWith('.formTrigger');
  });
  const pick = trigLike.length ? trigLike : roots;
  if (pick.length > 1) throw new Error('Multiple orphan roots unsupported.');
  return pick[0].name;
}
function graphToSdk(wfInner, overrides) {
  const nodesSrc = wfInner.activeVersion?.nodes?.length ? wfInner.activeVersion.nodes : wfInner.nodes;
  const connsSrc = wfInner.activeVersion?.connections ?? wfInner.connections ?? {};
  if (!nodesSrc?.length) throw new Error('Workflow has no nodes.');
  const byName = Object.fromEntries(nodesSrc.map((n) => [n.name, n]));
  const root = chooseTriggerRootName(nodesSrc, connsSrc);
  const path = linearPath(root, connsSrc, 96);
  const baseTitle = wfInner.name || 'workflow';
  const titled = overrides.title ? String(overrides.title).trim().slice(0, 128) : baseTitle.slice(0, 128);
  const finalTitle = sanitizeJsString(titled);
  const slug = slugify(titled.replace(/[^\x20-\x7E]+/g, ''));
  let code = 'import { workflow, node, trigger } from "@n8n/workflow-sdk";\n\n';
  path.forEach((nm, idx) => {
    const n = byName[nm];
    if (!n) throw new Error('Missing node ' + nm);
    const t = String(n.type || '');
    const isTrig = (
      t.endsWith('Trigger')
      || t.includes('postgresTrigger')
      || t.endsWith('.webhook')
      || t.includes('chatTrigger')
      || t.endsWith('.formTrigger')
    );
    const vn = 'step' + idx;
    const tv = Number.isFinite(Number(n.typeVersion)) ? Number(n.typeVersion) : 1;
    const params = JSON.stringify(n.parameters ?? {});
    const innerBody = '{\n      name: "' + sanitizeJsString(String(n.name || vn)) + '",\n      parameters: (' + params + ') as unknown as Record<string, unknown>,\n    }';
    const factory = isTrig ? 'trigger' : 'node';
    code += 'const ' + vn + ' = ' + factory + '({\n  type: "' + sanitizeJsString(t) + '",\n  version: ' + tv + ',\n  config: ' + innerBody + ',\n});\n\n';
  });
  let tail = '.add(step0)';
  for (let i = 1; i < path.length; i++) tail += '.to(step' + i + ')';
  code += 'export default workflow("' + slug + '", "' + finalTitle + '")' + tail + ';\n';
  let desc = wfInner.description != null ? String(wfInner.description) : '';
  if (overrides.description != null && String(overrides.description).trim()) {
    desc = String(overrides.description).trim();
  }
  desc = desc.slice(0, 255);
  return { code, name: titled, description: desc };
}


function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/?
/).find((line) => line.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP response: ' + text.slice(0, 400));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const contentText = payload.result?.content?.[0]?.text;
  if (contentText) {
    try { return JSON.parse(contentText); } catch { return {}; }
  }
  return payload.result?.structuredContent || {};
}

const packed = $('Build SDK Payload').first().json;
const raw = $('MCP Validate').first().json.body ?? $('MCP Validate').first().json.data ?? '';
const details = parseMcpSse(raw);
const wfInner = details.workflow || details;
if (!wfInner?.nodes?.length) throw new Error('Unexpected get_workflow_details payload');
const overrides = {};
if (packed.workflowName && String(packed.workflowName).trim() !== '') {
  overrides.title = String(packed.workflowName).trim();
}
if (packed.description !== undefined && String(packed.description).trim() !== '') {
  overrides.description = String(packed.description).trim();
}
let graphNote = '';
if (packed.active !== undefined && String(packed.active).trim() !== '') {
  graphNote = 'Note: toggle active with SK - Activate/Deactivate Workflow.';
}
let built;
try {
  built = graphToSdk(wfInner, overrides);
} catch (e) {
  throw new Error('Cannot build SDK update payload: ' + e.message);
}
return [{
  json: {
    ...packed,
    graphNote,
    updateRpc: {
      jsonrpc: '2.0',
      id: 2,
      method: 'tools/call',
      params: {
        name: 'update_workflow',
        arguments: {
          workflowId: packed.workflowId,
          code: built.code,
          name: built.name,
          description: built.description,
        },
      },
    },
  },
}];

