const packed = $('Parse Validate').first().json;
const http = $input.first().json;
const out = parseMcpSse(http.body ?? http.data ?? '');
return [{
  json: {
    success: true,
    workflowId: out.workflowId,
    name: out.name,
    url: out.url,
    nodeCount: out.nodeCount,
    graphNote: packed.graphNote || '',
    response: out.url ? ('Updated workflow "' + String(out.name) + '". Open ' + String(out.url)) : JSON.stringify(out).slice(0, 800),
